#!/usr/bin/perl
use strict;
use warnings;
use Carp qw(croak);

# =============================================================================
# Flexible Validation System
# Validates user input against configurable regex patterns
# Uses safe compilation of user-provided patterns with error handling
# =============================================================================

package ValidationSystem;

sub new {
    my ($class, %opts) = @_;
    my $self = {
        patterns      => {},
        compiled      => {},
        max_pattern_len => $opts{max_pattern_len} || 500,
        timeout        => $opts{timeout} || 2,
    };
    return bless $self, $class;
}

# Sanitize and validate the regex pattern before compilation
sub _sanitize_pattern {
    my ($self, $pattern) = @_;

    croak "Pattern is undefined" unless defined $pattern;
    croak "Pattern is empty" unless length $pattern;
    croak "Pattern exceeds maximum length ($self->{max_pattern_len})"
        if length($pattern) > $self->{max_pattern_len};

    # Block dangerous constructs that could allow code execution
    # (?{ code }) and (??{ code }) are the main threats in Perl regex
    if ($pattern =~ /\(\s*\?\s*\?\?\s*\{/ || $pattern =~ /\(\s*\?\s*\{/) {
        croak "Pattern contains prohibited embedded code construct: $pattern";
    }

    # Block attempts to escape regex context
    if ($pattern =~ /(?:\\x[0-9a-fA-F]{2}){4,}/) {
        # Allow short hex escapes but block suspiciously long sequences
        warn "Warning: Pattern contains long hex escape sequences\n";
    }

    return $pattern;
}

# Safely compile a regex pattern using eval with error trapping
sub compile_pattern {
    my ($self, $name, $pattern, %opts) = @_;

    my $flags = $opts{flags} || '';

    # Validate flags - only allow safe regex flags
    if ($flags =~ /[^imsxadlup]/) {
        croak "Invalid regex flags: $flags (allowed: i, m, s, x, a, d, l, u, p)";
    }

    # Sanitize the pattern
    my $safe_pattern = $self->_sanitize_pattern($pattern);

    # Compile the regex safely using qr// inside eval
    # This prevents arbitrary code execution while still allowing
    # dynamic pattern compilation
    my $compiled;
    {
        # Use 'use re "eval"' is intentionally NOT enabled here
        # to prevent (?{ }) code execution even if our check above is bypassed
        local $@;
        $compiled = eval {
            # Alarm-based timeout to prevent ReDoS
            local $SIG{ALRM} = sub { die "Pattern compilation timed out\n" };
            alarm($self->{timeout});

            my $re;
            if ($flags) {
                $re = qr/(?$flags)$safe_pattern/;
            } else {
                $re = qr/$safe_pattern/;
            }

            alarm(0);
            return $re;
        };
        alarm(0);  # Ensure alarm is cleared

        if ($@ || !defined $compiled) {
            my $error = $@ || "Unknown compilation error";
            chomp $error;
            croak "Failed to compile pattern '$name': $error";
        }
    }

    $self->{patterns}{$name} = {
        source   => $pattern,
        flags    => $flags,
        compiled => $compiled,
        description => $opts{description} || '',
    };

    return $compiled;
}

# Load patterns from a configuration hash
sub load_config {
    my ($self, $config) = @_;

    croak "Config must be a hash reference" unless ref $config eq 'HASH';

    my @loaded;
    my @errors;

    for my $name (sort keys %$config) {
        my $entry = $config->{$name};
        my ($pattern, $flags, $desc);

        if (ref $entry eq 'HASH') {
            $pattern = $entry->{pattern};
            $flags   = $entry->{flags} || '';
            $desc    = $entry->{description} || '';
        } else {
            $pattern = $entry;
            $flags   = '';
            $desc    = '';
        }

        eval {
            $self->compile_pattern($name, $pattern,
                flags       => $flags,
                description => $desc,
            );
            push @loaded, $name;
        };
        if ($@) {
            push @errors, { name => $name, error => $@ };
        }
    }

    return { loaded => \@loaded, errors => \@errors };
}

# Validate a string against a named pattern
sub validate {
    my ($self, $name, $input) = @_;

    croak "Unknown pattern: '$name'"
        unless exists $self->{patterns}{$name};

    croak "Input is undefined" unless defined $input;

    my $compiled = $self->{patterns}{$name}{compiled};

    # Execute the match with a timeout to prevent ReDoS
    my $matched;
    eval {
        local $SIG{ALRM} = sub { die "Pattern match timed out (possible ReDoS)\n" };
        alarm($self->{timeout});
        $matched = ($input =~ $compiled) ? 1 : 0;
        alarm(0);
    };
    alarm(0);  # Ensure alarm is cleared

    if ($@) {
        chomp(my $error = $@);
        return {
            valid   => 0,
            error   => $error,
            pattern => $name,
            input   => $input,
        };
    }

    return {
        valid   => $matched,
        pattern => $name,
        input   => $input,
        error   => undef,
    };
}

# Validate against multiple patterns at once
sub validate_all {
    my ($self, $input, @pattern_names) = @_;

    my @results;
    my $all_valid = 1;

    for my $name (@pattern_names) {
        my $result = $self->validate($name, $input);
        push @results, $result;
        $all_valid = 0 unless $result->{valid};
    }

    return {
        all_valid => $all_valid,
        results   => \@results,
    };
}

# Test a one-off pattern against input without storing it
sub test_pattern {
    my ($self, $pattern, $input, %opts) = @_;

    my $temp_name = "__temp_" . time() . "_$$";

    eval {
        $self->compile_pattern($temp_name, $pattern, %opts);
    };
    if ($@) {
        return { valid => 0, error => $@, compiled => 0 };
    }

    my $result = $self->validate($temp_name, $input);
    delete $self->{patterns}{$temp_name};

    $result->{compiled} = 1;
    return $result;
}

# List all loaded patterns
sub list_patterns {
    my ($self) = @_;
    my @info;
    for my $name (sort keys %{$self->{patterns}}) {
        push @info, {
            name        => $name,
            source      => $self->{patterns}{$name}{source},
            flags       => $self->{patterns}{$name}{flags},
            description => $self->{patterns}{$name}{description},
        };
    }
    return @info;
}

# Remove a pattern
sub remove_pattern {
    my ($self, $name) = @_;
    return delete $self->{patterns}{$name};
}

